<section class="card"><h2>Audit trail</h2><table><thead><tr><th>Timestamp</th><th>User</th><th>Action</th><th>Entity</th><th>Data</th></tr></thead><tbody><?php foreach ($logs as $log): ?><tr><td><?= e($log['created_at']) ?></td><td><?= e($log['full_name'] ?? 'System') ?></td><td><?= e($log['action']) ?></td><td><?= e($log['entity_type']) ?></td><td><details><summary>JSON</summary><pre><?= e(json_encode(['old'=>$log['old_data'], 'new'=>$log['new_data']], JSON_PRETTY_PRINT)) ?></pre></details></td></tr><?php endforeach; ?></tbody></table></section>
